```js
async function rateLimitMiddleware(req, res, next) {
  const today = new Date().toISOString().split('T')[0];
  const key = `ratelimit:${req.user.id}:${today}`;
  const limit = req.user.plan === 'pro' ? 100 : 10;
  const count = await redis.incr(key);
  if (count === 1) await redis.expire(key, 86400); // 24h TTL
  res.setHeader('X-RateLimit-Remaining', Math.max(0, limit - count));
  if (count > limit) return res.status(429).json({ error: 'Daily limit reached. Upgrade to Pro for more.' });
  next();
}
```
Always set the TTL on first increment to avoid stale keys accumulating forever.
